ground_truth.fix:
def find_cheapest(products):
    """Return the product with the lowest price."""
    if not products:
        return None
    cheapest = products[0]
    for product in products[1:]:
        if float(product['price']) < float(cheapest['price']):
            cheapest = product
    return cheapest

def is_affordable(product, budget):
    """Check if a product is within budget."""
    return float(product['price']) <= float(budget)

